def build_package_tarball(
    name: str,
    version: str,
    package_json_extra: dict[str, object],
    files: dict[str, str],
) -> bytes:
    package_json = {
        "name": name,
        "version": version,
        **package_json_extra,
    }
    tar_stream = io.BytesIO()

    with tarfile.open(fileobj=tar_stream, mode="w:gz") as archive:
        add_tar_text_file(
            archive,
            "package/package.json",
            json.dumps(package_json, separators=(",", ":")),
        )
        add_tar_text_file(archive, "package/index.js", "module.exports = 'ok'\n")
        for rel_path, content in files.items():
            add_tar_text_file(archive, f"package/{rel_path}", content)

    return tar_stream.getvalue()


def add_tar_text_file(archive: tarfile.TarFile, path: str, content: str) -> None:
    data = content.encode("utf-8")
    info = tarfile.TarInfo(path)
    info.size = len(data)
    info.mode = 0o755 if path.endswith(".js") else 0o644
    archive.addfile(info, io.BytesIO(data))


def compute_sha512_sri(content: bytes) -> str:
    integrity = base64.b64encode(hashlib.sha512(content).digest()).decode("ascii")
    return f"sha512-{integrity}"


def build_registry_version_metadata(
    registry_url: str,
    name: str,
    version: str,
    tarball: bytes,
    metadata_extra: dict[str, object],
) -> dict[str, object]:
    return {
        "name": name,
        "version": version,
        "dist": {
            "tarball": f"{registry_url}tarballs/{name}/-/{name}-{version}.tgz",
            "integrity": compute_sha512_sri(tarball),
        },
        **metadata_extra,
    }


def write_package_json(path: Path, payload: dict[str, object]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, indent=4) + "\n", encoding="utf-8")


def read_json_file(path: Path) -> dict[str, object]:
    return json.loads(path.read_text(encoding="utf-8"))


def write_signed_project_unlock(
    home_root: str | Path,
    project_root: str | Path,
    *,
    scopes: list[str],
    ttl_seconds: int = 600,
) -> None:
    now = datetime.now(timezone.utc)
    payload = {
        "schema_version": 1,
        "id": f"unl_{time.time_ns()}",
        "target": "project",
        "project_root": str(Path(project_root).resolve()),
        "scopes": scopes,
        "limits": {},
        "issued_at": now.isoformat().replace("+00:00", "Z"),
        "expires_at": (now + timedelta(seconds=ttl_seconds)).isoformat().replace("+00:00", "Z"),
        "issuer": "user-presence",
    }

    secret = bytes([42]) * 32
    security_dir = Path(home_root) / ".lpm" / "security"
    unlocks_dir = security_dir / "unlocks"
    unlocks_dir.mkdir(parents=True, exist_ok=True)
    (security_dir / "signing-secret.hex").write_text(secret.hex(), encoding="utf-8")

    payload_bytes = json.dumps(payload, separators=(",", ":")).encode("utf-8")
    signature = hmac.new(secret, payload_bytes, hashlib.sha256).hexdigest()
    envelope = {
        "payload": payload,
        "signature": signature,
    }
    unlocks_dir.joinpath(f"{payload['id']}.json").write_text(
        json.dumps(envelope, indent=2) + "\n",
        encoding="utf-8",
    )


