def resolve_global_shim_path(lpm_home: str, command_name: str) -> Path:
    bin_dir = Path(lpm_home) / "bin"
    for candidate in [
        bin_dir / command_name,
        bin_dir / f"{command_name}.cmd",
        bin_dir / f"{command_name}.exe",
    ]:
        if candidate.exists():
            return candidate
    return bin_dir / command_name


def run_command_result(
    label: str,
    cwd: Path,
    args: list[str],
    extra_env: dict[str, str | None] | None = None,
) -> subprocess.CompletedProcess[str]:
    log(f"{label}: {' '.join(args)}")
    result = subprocess.run(
        args,
        cwd=cwd,
        env=merged_env(extra_env),
        capture_output=True,
        text=True,
    )

    if result.stdout:
        sys.stdout.write(result.stdout)
    if result.stderr:
        sys.stderr.write(result.stderr)

    return result


def run_command(
    label: str,
    cwd: Path,
    args: list[str],
    extra_env: dict[str, str | None] | None = None,
) -> str:
    result = run_command_result(label, cwd, args, extra_env=extra_env)

    combined = result.stdout + result.stderr
    if result.returncode != 0:
        raise SmokeFailure(f"{label} failed with exit code {result.returncode}")
    return combined


def run_command_expect_failure(
    label: str,
    cwd: Path,
    args: list[str],
    extra_env: dict[str, str | None] | None = None,
) -> str:
    result = run_command_result(label, cwd, args, extra_env=extra_env)

    combined = result.stdout + result.stderr
    if result.returncode == 0:
        raise SmokeFailure(f"{label} unexpectedly succeeded")
    return combined


def run_interactive_command_result(
    label: str,
    cwd: Path,
    args: list[str],
    prompts: list[tuple[str, str]],
    extra_env: dict[str, str | None] | None = None,
    timeout_seconds: int = 600,
) -> tuple[str, int]:
    log(f"{label}: {' '.join(args)}")
    env = merged_env(extra_env)
    pid, fd = pty.fork()

    if pid == 0:
        os.chdir(cwd)
        os.execvpe(args[0], args, env)

    transcript = ""
    next_prompt = 0
    deadline = time.monotonic() + timeout_seconds

    while True:
        if time.monotonic() > deadline:
            os.close(fd)
            os.kill(pid, 9)
            os.waitpid(pid, 0)
            raise SmokeFailure(f"{label} timed out waiting for interactive completion")

        ready, _, _ = select.select([fd], [], [], 0.1)
        if fd in ready:
            try:
                chunk = os.read(fd, 4096)
            except OSError:
                chunk = b""

            if chunk:
                decoded = chunk.decode("utf-8", errors="replace")
                transcript += decoded
                sys.stdout.write(decoded)
                sys.stdout.flush()

                while next_prompt < len(prompts) and prompts[next_prompt][0] in transcript:
                    os.write(fd, prompts[next_prompt][1].encode("utf-8"))
                    next_prompt += 1

        finished_pid, status = os.waitpid(pid, os.WNOHANG)
        if finished_pid == pid:
            os.close(fd)
            if os.WIFEXITED(status):
                exit_code = os.WEXITSTATUS(status)
            elif os.WIFSIGNALED(status):
                exit_code = 128 + os.WTERMSIG(status)
            else:
                exit_code = 1

            return transcript, exit_code


def run_interactive_command(
    label: str,
    cwd: Path,
    args: list[str],
    prompts: list[tuple[str, str]],
    extra_env: dict[str, str] | None = None,
    timeout_seconds: int = 600,
) -> str:
    transcript, exit_code = run_interactive_command_result(
        label,
        cwd,
        args,
        prompts,
        extra_env=extra_env,
        timeout_seconds=timeout_seconds,
    )
    if exit_code != 0:
        raise SmokeFailure(f"{label} failed with exit code {exit_code}")
    return transcript


def parse_json_stdout(label: str, result: subprocess.CompletedProcess[str]) -> dict[str, object]:
    try:
        payload = json.loads(result.stdout)
    except json.JSONDecodeError as error:
        raise SmokeFailure(
            f"{label}: expected JSON on stdout, got {result.stdout!r}"
        ) from error

    if not isinstance(payload, dict):
        raise SmokeFailure(f"{label}: expected top-level JSON object")
    return payload


def parse_json_stdout_stream(
    label: str,
    result: subprocess.CompletedProcess[str],
) -> list[dict[str, object]]:
    decoder = json.JSONDecoder()
    payloads: list[dict[str, object]] = []
    raw = result.stdout
    index = 0

    while index < len(raw):
        while index < len(raw) and raw[index].isspace():
            index += 1
        if index >= len(raw):
            break
        try:
            payload, next_index = decoder.raw_decode(raw, index)
        except json.JSONDecodeError as error:
            raise SmokeFailure(
                f"{label}: expected a JSON object stream on stdout, got {result.stdout!r}"
            ) from error
        if not isinstance(payload, dict):
            raise SmokeFailure(f"{label}: expected each JSON payload to be an object")
        payloads.append(payload)
        index = next_index

    if not payloads:
        raise SmokeFailure(f"{label}: expected at least one JSON payload on stdout")
    return payloads


def require_success_payload(
    label: str,
    result: subprocess.CompletedProcess[str],
    payload_key: str,
) -> dict[str, object]:
    if result.returncode != 0:
        raise SmokeFailure(f"{label} failed with exit code {result.returncode}")

    envelope = parse_json_stdout(label, result)
    if envelope.get("success") is not True:
        raise SmokeFailure(f"{label}: expected success=true JSON envelope")

    payload = envelope.get(payload_key)
    if not isinstance(payload, dict):
        raise SmokeFailure(f"{label}: expected `{payload_key}` object in JSON envelope")
    return payload


def require_security_approval_envelope(
    label: str,
    result: subprocess.CompletedProcess[str],
    expected_scope: str,
) -> dict[str, object]:
    if result.returncode == 0:
        raise SmokeFailure(f"{label}: unexpectedly succeeded")

    envelope = parse_json_stdout(label, result)
    if envelope.get("success") is not False:
        raise SmokeFailure(f"{label}: expected success=false JSON envelope")

    error = envelope.get("error")
    if not isinstance(error, dict):
        raise SmokeFailure(f"{label}: expected error object in JSON envelope")
    if error.get("code") != "SECURITY_APPROVAL_REQUIRED":
        raise SmokeFailure(
            f"{label}: expected SECURITY_APPROVAL_REQUIRED, got {error.get('code')!r}"
        )

    requested_scopes = error.get("requested_scopes")
    if not isinstance(requested_scopes, list) or expected_scope not in requested_scopes:
        raise SmokeFailure(
            f"{label}: expected requested_scopes to include {expected_scope!r}, got {requested_scopes!r}"
        )
    return envelope


def require_audit_event(
    rows: list[dict[str, object]],
    *,
    event: str,
    allowed: bool,
    expected_scope: str,
    context: str,
) -> dict[str, object]:
    for row in rows:
        candidate = row.get("payload") if isinstance(row.get("payload"), dict) else row
        scopes = candidate.get("scopes") if isinstance(candidate, dict) else None
        if (
            isinstance(candidate, dict)
            and candidate.get("event") == event
            and candidate.get("allowed") == allowed
            and isinstance(scopes, list)
            and expected_scope in scopes
        ):
            return candidate

    raise SmokeFailure(
        f"{context}: expected audit event {event!r} allowed={allowed} scope={expected_scope!r}"
    )


def require_contains(text: str, needle: str, context: str) -> None:
    if needle not in text:
        raise SmokeFailure(f"{context}: expected to find {needle!r}")


def require_not_contains(text: str, needle: str, context: str) -> None:
    if needle in text:
        raise SmokeFailure(f"{context}: did not expect to find {needle!r}")


def require_exists(path: Path) -> None:
    if not path.exists():
        raise SmokeFailure(f"expected path to exist: {path}")


def require_not_exists(path: Path) -> None:
    if path.exists() or path.is_symlink():
        raise SmokeFailure(f"expected path to be absent: {path}")


def lockfile_binary_supported(lockfile_path: Path) -> bool:
    with lockfile_path.open("rb") as handle:
        document = tomllib.load(handle)

    if document.get("importers"):
        return False
    if document.get("patches"):
        return False
    if document.get("root-aliases") or document.get("root_aliases"):
        return False
    if document.get("ambient-peer-installs") or document.get("ambient_peer_installs"):
        return False
    metadata = document.get("metadata")
    if isinstance(metadata, dict) and (
        metadata.get("auto-isolated-peer-conflicts")
        or metadata.get("auto_isolated_peer_conflicts")
    ):
        return False
    if document.get("catalogs"):
        return False

    unsupported_package_keys = {
        "alias-dependencies",
        "alias_dependencies",
        "peers",
        "os",
        "cpu",
        "libc",
        "registry-signatures",
        "registry_signatures",
        "registry-published-at",
        "registry_published_at",
    }
    for package in document.get("packages", []):
        if not isinstance(package, dict):
            continue
        if package.get("optional") is True:
            return False
        for key in unsupported_package_keys:
            value = package.get(key)
            if value:
                return False
    return True


def require_lockfile_binary_matches_toml(project_dir: Path, context: str) -> None:
    lockfile_path = project_dir / "lpm.lock"
    lockfile_binary_path = project_dir / "lpm.lockb"
    require_exists(lockfile_path)
    if lockfile_binary_supported(lockfile_path):
        if not lockfile_binary_path.exists():
            raise SmokeFailure(
                f"{context}: expected lpm.lockb for binary-compatible lockfile"
            )
    elif lockfile_binary_path.exists() or lockfile_binary_path.is_symlink():
        raise SmokeFailure(
            f"{context}: expected no lpm.lockb for TOML-only lockfile metadata"
        )


def require_directory_empty_or_absent(path: Path, context: str) -> None:
    if not path.exists():
        return
    if any(path.iterdir()):
        raise SmokeFailure(f"{context}: expected directory to be absent or empty, got entries under {path}")


def ensure_lpm_binary() -> None:
    run_command(
        "build lpm-cli",
        RUST_CLIENT_ROOT,
        [
            "cargo",
            "build",
            "--manifest-path",
            str(LPM_MANIFEST),
            "-p",
            "lpm-cli",
        ],
    )
    require_exists(LPM_BIN)


