    with tempfile.TemporaryDirectory(prefix="lpmdld-dup-", dir="/tmp") as root:
        root_path = Path(root)
        project_a = root_path / "a"
        project_b = root_path / "b"
        home_dir = root_path / "h"
        env_shared = base_env(home_dir)
