def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Run live smoke scenarios in test-packages.")
    parser.add_argument(
        "scenarios",
        nargs="*",
        default=["all"],
        help="Scenario names to run. Use 'all' for every non-opt-in scenario.",
    )
    parser.add_argument("--list", action="store_true", help="List available scenarios and exit.")
    return parser.parse_args()


def main() -> int:
    args = parse_args()

    if args.list:
        for name, (description, _) in SCENARIOS.items():
            opt_in = " [opt-in]" if name in OPT_IN_SCENARIOS else ""
            print(f"{name}{opt_in}: {description}")
        return 0

    requested = args.scenarios
    if "all" in requested:
        selected = [name for name in SCENARIOS if name not in OPT_IN_SCENARIOS]
    else:
        selected = requested

    unknown = [name for name in selected if name not in SCENARIOS]
    if unknown:
        raise SmokeFailure(f"unknown scenario(s): {', '.join(unknown)}")

    with preserve_fixture_trees(MUTABLE_FIXTURE_TREES):
        ensure_lpm_binary()

        for name in selected:
            description, scenario = SCENARIOS[name]
            log(f"starting {name}: {description}")
            with isolated_default_smoke_home():
                scenario()
            log(f"finished {name}")

    log("all requested scenarios passed")
    return 0


if __name__ == "__main__":
    try:
        raise SystemExit(main())
    except SmokeFailure as error:
        print(f"[smoke] FAILURE: {error}", file=sys.stderr)
        raise SystemExit(1)
